// Grab the cleaned content from Jina Reader
const rawContent = $input.first().json.data 
  || $input.first().json.body 
  || '';

// Get user context from the original trigger
const triggerData = $('Telegram Trigger').first().json;
const chatId = triggerData.message.chat.id;
const userId = triggerData.message.from.id;
const fullMessage = triggerData.message.text;

// Extract the URL from "/learn URL" pattern
const url = fullMessage.replace('/learn', '').trim();

// Convert to string if needed
let content = typeof rawContent === 'string' 
  ? rawContent 
  : JSON.stringify(rawContent);

// Remove excessive whitespace
content = content.replace(/\n{3,}/g, '\n\n').trim();

// Check if extraction actually worked
if (content.length < 200) {
  return [{
    json: {
      chatId,
      userId,
      url,
      error: true,
      errorMessage: '❌ I could not extract meaningful content from that URL. The page might be behind a paywall, require JavaScript, or be empty.'
    }
  }];
}

// Cap length to keep LLM costs reasonable (~3000 tokens of input)
const MAX_LENGTH = 12000;
if (content.length > MAX_LENGTH) {
  content = content.substring(0, MAX_LENGTH) + '\n\n[Content truncated for length]';
}

return [{
  json: {
    chatId,
    userId,
    url,
    content,
    contentLength: content.length,
    error: false
  }
}];

const chatId = $('Prepare Content').first().json.chatId;

// Get the summary from the LLM - correct path based on your screenshot
const rawSummary = $input.first().json.content?.[0]?.text 
  || $input.first().json.output?.[0]?.content?.[0]?.text
  || '';

if (!rawSummary) {
  return [{
    json: {
      chatId,
      summary: '❌ Failed to generate summary. Please try again.',
      error: true
    }
  }];
}

// Function to escape markdown for Telegram MarkdownV2
function escapeForMarkdownV2(text) {
  // Step 1: Store bold sections with placeholders
  const boldSections = [];
  let textWithPlaceholders = text.replace(/\*([^*]+)\*/g, (match, content) => {
    boldSections.push(content);
    return `§BOLD${boldSections.length - 1}§`;
  });

  // Step 2: Escape all special characters for MarkdownV2
  // These characters must be escaped: _ * [ ] ( ) ~ ` > # + - = | { } . !
  const escapeChars = ['_', '*', '[', ']', '(', ')', '~', '`', '>', '#', '+', '-', '=', '|', '{', '}', '.', '!'];

  escapeChars.forEach(char => {
    const regex = new RegExp('\\' + char, 'g');
    textWithPlaceholders = textWithPlaceholders.replace(regex, '\\' + char);
  });

  // Step 3: Restore bold formatting with escaped content
  boldSections.forEach((content, index) => {
    // Escape the content inside bold tags too
    let escapedContent = content;
    escapeChars.forEach(char => {
      const regex = new RegExp('\\' + char, 'g');
      escapedContent = escapedContent.replace(regex, '\\' + char);
    });

    textWithPlaceholders = textWithPlaceholders.replace(
      `§BOLD${index}§`,
      `*${escapedContent}*`
    );
  });

  return textWithPlaceholders;
}

const escapedSummary = escapeForMarkdownV2(rawSummary);

return [{
  json: {
    chatId,
    summary: escapedSummary,
    rawSummary: rawSummary // Keep for debugging
  }
}];

const chatId = $('Prepare Content').first().json.chatId;
const userId = $('Prepare Content').first().json.userId;
const url = $('Prepare Content').first().json.url;
const content = $('Prepare Content').first().json.content;

// Get the LLM's JSON output - try multiple possible paths
const rawOutput = $input.first().json.content?.[0]?.text 
  || $input.first().json.output?.[0]?.content?.[0]?.text
  || $input.first().json.message?.content
  || $input.first().json.choices?.[0]?.message?.content
  || $input.first().json.text
  || '';

let quiz;
try {
  // Remove markdown code fences if present
  let cleaned = rawOutput.trim();
  cleaned = cleaned.replace(/```json\n?/g, '').replace(/```\n?/g, '');
  quiz = typeof cleaned === 'string' ? JSON.parse(cleaned) : cleaned;
} catch (e) {
  console.error('Quiz parse error:', e);
  return [{
    json: {
      chatId,
      error: true,
      errorMessage: '❌ I had trouble building a quiz this time. Try another article!'
    }
  }];
}

// Validate structure
if (!quiz.questions || !Array.isArray(quiz.questions) || quiz.questions.length === 0) {
  return [{
    json: {
      chatId,
      error: true,
      errorMessage: '❌ Quiz generation returned an unexpected format. Try another article!'
    }
  }];
}

// Ensure we have at least 3 questions
if (quiz.questions.length < 3) {
  return [{
    json: {
      chatId,
      error: true,
      errorMessage: `❌ Could only generate ${quiz.questions.length} questions. Try a longer article!`
    }
  }];
}

// ===== THIS IS THE CRITICAL PART =====
// Get static data storage
const staticData = $getWorkflowStaticData('global');

// Extract title from the summary
const summaryText = $('Format Summary').first().json.summary || '';
const titleMatch = summaryText.match(/<b>Title<\/b>:\s*([^<\n]+)/i) 
  || summaryText.match(/Title[*:\s]+([^\n]+)/i);
let topicTitle = titleMatch ? titleMatch[1].trim() : 'Untitled Topic';

// Clean HTML tags
topicTitle = topicTitle.replace(/<[^>]+>/g, '').trim();

// Limit title length
if (topicTitle.length > 60) {
  topicTitle = topicTitle.substring(0, 57) + '...';
}

// Initialize learned topics storage if it doesn't exist
if (!staticData.learnedTopics) {
  staticData.learnedTopics = {};
  console.log('Initialized learnedTopics object');
}

// Initialize array for this user if it doesn't exist
if (!staticData.learnedTopics[chatId]) {
  staticData.learnedTopics[chatId] = [];
  console.log('Initialized array for chatId:', chatId);
}

// Create a unique topic ID
const topicId = `topic_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

// THIS IS WHERE THE TOPIC GETS SAVED
staticData.learnedTopics[chatId].unshift({
  id: topicId,
  title: topicTitle,
  url: url,
  content: content,
  questions: quiz.questions.slice(0, 3),
  learnedAt: Date.now()
});

console.log('✅ Topic saved! chatId:', chatId, 'topicTitle:', topicTitle);
console.log('Total topics for this user:', staticData.learnedTopics[chatId].length);

// Keep only last 10 topics
if (staticData.learnedTopics[chatId].length > 10) {
  staticData.learnedTopics[chatId] = staticData.learnedTopics[chatId].slice(0, 10);
}

// Store current quiz session (not used since quiz doesn't auto-start)
staticData[`quiz_${chatId}`] = {
  userId,
  url,
  topicId,
  topicTitle,
  questions: quiz.questions.slice(0, 3),
  currentIndex: 0,
  score: 0,
  startedAt: Date.now()
};

return [{
  json: {
    chatId,
    error: false,
    topicTitle,
    topicSaved: true
  }
}];

const chatId = $input.first().json.message.chat.id;
const userId = $input.first().json.message.from.id;

// Access the static data storage
const staticData = $getWorkflowStaticData('global');

// Get learned topics for this specific user
const learnedTopics = staticData.learnedTopics?.[chatId] || [];

// Check if user has any learned topics
if (learnedTopics.length === 0) {
  return [{
    json: {
      chatId,
      userId,
      noTopics: true,
      message: '📚 <b>Ain’t Nothin’ Here Yet.</b>\n\nMan, you ain’t learned a single thing so far.\n\nUse <code>/learn [URL]</code> first so I got somethin’ to work with. Then you can do quizzes and all that.\n\n<b>Example:</b>\n<code>/learn https://en.wikipedia.org/wiki/Photosynthesis</code>\n\nAight?'
    }
  }];
}

// User has topics - prepare them for display
// Limit to 8 most recent (Telegram button limit per message)
const topicsForDisplay = learnedTopics.slice(0, 8);

return [{
  json: {
    chatId,
    userId,
    noTopics: false,
    topics: topicsForDisplay,
    topicCount: learnedTopics.length
  }
}];

const chatId = $input.first().json.chatId;
const topics = $input.first().json.topics;
const topicCount = $input.first().json.topicCount;

// Build the message text
const messageText = `🧠 <b>Select a Topic to Quiz On</b>\n\nChoose from your ${topicCount > 8 ? '8 most recent' : topicCount} learned topic${topicCount > 1 ? 's' : ''}:`;

// Build inline keyboard buttons
// Each button will have the topic title and a callback_data with the topic ID
const buttons = topics.map(topic => {
  // Format the learned date for display
  const learnedDate = new Date(topic.learnedAt);
  const dateStr = learnedDate.toLocaleDateString('en-US', { 
    month: 'short', 
    day: 'numeric' 
  });

  return {
    text: `📖 ${topic.title}`,
    callback_data: `quiz_${topic.id}`  // This is what gets sent when user taps
  };
});

return [{
  json: {
    chatId,
    messageText,
    buttons,
    topicCount
  }
}];

const chatId = $input.first().json.chatId;
const messageText = $input.first().json.messageText;
const buttons = $input.first().json.buttons;

// Build inline keyboard - each button on its own row
const inlineKeyboard = buttons.map(button => [button]);

// Return everything needed for the HTTP Request node
return [{
  json: {
    chatId: chatId,
    text: messageText,
    parse_mode: 'HTML',
    reply_markup: JSON.stringify({
      inline_keyboard: inlineKeyboard
    })
  }
}];

const callback = $input.first().json.callback_query;
const chatId = callback.message.chat.id;
const userId = callback.from.id;
const callbackQueryId = callback.id;
const callbackData = callback.data;

console.log('🎯 Topic button tapped!');
console.log('Callback data:', callbackData);

// Extract topic ID (remove "quiz_" prefix)
const topicId = callbackData.replace('quiz_', '');
console.log('Looking for topic ID:', topicId);

// Get stored topics
const staticData = $getWorkflowStaticData('global');
const learnedTopics = staticData.learnedTopics?.[chatId] || [];
console.log('Total topics stored:', learnedTopics.length);

// Find the selected topic
const selectedTopic = learnedTopics.find(topic => topic.id === topicId);

if (!selectedTopic) {
  console.error('❌ Topic not found!');
  console.error('Available topic IDs:', learnedTopics.map(t => t.id));

  return [{
    json: {
      chatId,
      callbackQueryId,
      error: true,
      errorMessage: '❌ <b>Topic Not Found</b>\n\nThis topic is no longer available.'
    }
  }];
}

console.log('✅ Topic found:', selectedTopic.title);
console.log('Questions available:', selectedTopic.questions.length);

// Create quiz session
staticData[`quiz_${chatId}`] = {
  userId,
  topicId: selectedTopic.id,
  topicTitle: selectedTopic.title,
  questions: selectedTopic.questions,
  currentIndex: 0,
  score: 0,
  startedAt: Date.now()
};

console.log('✅ Quiz session created for chat:', chatId);

// Get first question
const firstQ = selectedTopic.questions[0];

return [{
  json: {
    chatId,
    callbackQueryId,
    error: false,
    topicTitle: selectedTopic.title,
    questionNumber: 1,
    totalQuestions: selectedTopic.questions.length,
    question: firstQ.question,
    options: firstQ.options
  }
}];

const callback = $input.first().json.callback_query;
const chatId = callback.message.chat.id;
const messageId = callback.message.message_id;
const userAnswer = callback.data;  // Will be "A", "B", "C", or "D"
const callbackQueryId = callback.id;

console.log('════════════════════════════════');
console.log('📝 Quiz Answer Received');
console.log('User answer:', userAnswer);
console.log('Chat ID:', chatId);
console.log('════════════════════════════════');

// Get the active quiz session
const staticData = $getWorkflowStaticData('global');
const quiz = staticData[`quiz_${chatId}`];

// Check if there's an active quiz
if (!quiz) {
  console.error('❌ No active quiz found');
  return [{
    json: {
      chatId,
      callbackQueryId,
      messageId,
      noQuiz: true,
      message: '❌ <b>No Active Quiz</b>\n\nNo quiz is currently running.\n\nUse <code>/quiz</code> to start a new quiz!',
      isDone: true
    }
  }];
}

console.log('Current quiz:', quiz.topicTitle);
console.log('Question:', quiz.currentIndex + 1, 'of', quiz.questions.length);

// Get the current question
const currentQuestion = quiz.questions[quiz.currentIndex];
console.log('Correct answer is:', currentQuestion.correct);

// Check if the answer is correct
const isCorrect = userAnswer === currentQuestion.correct;
console.log('User answered:', userAnswer, '→', isCorrect ? '✅ CORRECT' : '❌ WRONG');

// Update score if correct
if (isCorrect) {
  quiz.score++;
  console.log('Score updated:', quiz.score);
}

// Build feedback message
const feedback = isCorrect
  ? `✅ <b>Correct!</b>\n\n<i>${currentQuestion.explanation}</i>`
  : `❌ <b>Not quite.</b> The correct answer was <b>${currentQuestion.correct}</b>.\n\n<i>${currentQuestion.explanation}</i>`;

// Move to next question
quiz.currentIndex++;
console.log('Moving to question index:', quiz.currentIndex);

// Check if quiz is complete
const isDone = quiz.currentIndex >= quiz.questions.length;
console.log('Quiz complete?', isDone);

let responseMessage;
let hasNextQuestion = false;
let nextQuestion = null;

if (isDone) {
  // Quiz is complete - calculate final results
  const totalQuestions = quiz.questions.length;
  const percentage = Math.round((quiz.score / totalQuestions) * 100);

  console.log('════════════════════════════════');
  console.log('🏁 QUIZ COMPLETE');
  console.log('Final Score:', quiz.score, '/', totalQuestions, '(', percentage, '%)');
  console.log('════════════════════════════════');

  // Determine grade/emoji based on percentage
  let grade = '';
  let emoji = '';
  if (percentage === 100) {
    grade = '<b>Yeah, yeah. Look at you. Somehow got every answer right. Miracles happen, I guess.</b>';
    emoji = '🏆';
  } else if (percentage >= 67) {
    grade = '<b>Yeah, you pulled it off. Didn’t expect much, but here we are.</b>';
    emoji = '🎉';
  } else if (percentage >= 33) {
    grade = '<b>Aight, you tried. Coulda been worse, honestly.</b>';
    emoji = '👍';
  } else {
    grade = '<b>Yeah, you still got work to do. Go run it back till somethin’ actually sticks.</b>';
    emoji = '📚';
  }

  responseMessage = `${feedback}\n\n━━━━━━━━━━━━━━━━━━\n\n${emoji} <b>Quiz Complete!</b>\n\n<b>Topic:</b> ${quiz.topicTitle}\n<b>Your Score:</b> ${quiz.score}/${totalQuestions} (${percentage}%)\n\n${grade}\n\n<b>What's next?</b>\n• Use <code>/quiz</code> to review another topic\n• Use <code>/learn [URL]</code> to learn something new`;

  // Clear the active quiz session
  delete staticData[`quiz_${chatId}`];
  console.log('✅ Quiz session deleted');

} else {
  // More questions remaining
  nextQuestion = quiz.questions[quiz.currentIndex];
  const nextQuestionNumber = quiz.currentIndex + 1;

  console.log('Next question:', nextQuestionNumber, 'of', quiz.questions.length);

  responseMessage = `${feedback}\n\n━━━━━━━━━━━━━━━━━━\n\n<b>Question ${nextQuestionNumber}/${quiz.questions.length}:</b>\n\n${nextQuestion.question}\n\n${nextQuestion.options.join('\n')}`;

  hasNextQuestion = true;
}

return [{
  json: {
    chatId,
    messageId,
    callbackQueryId,
    message: responseMessage,
    isDone,
    hasNextQuestion,
    nextQuestion,
    noQuiz: false
  }
}];
